const { SQSClient, ReceiveMessageCommand, DeleteMessageCommand } = require("@aws-sdk/client-sqs");
const { DatabaseClient } = require("some-database-library"); // Replace with actual database library

const sqsClient = new SQSClient({ region: "your-region" });
const dbClient = new DatabaseClient();

async function processMessages() {
  const queueUrl = "your-queue-url";

  while (true) {
    try {
      const receiveMessageParams = {
        QueueUrl: queueUrl,
        AttributeNames: ["All"],
        MessageAttributeNames: ["All"],
        MaxNumberOfMessages: 10,
        WaitTimeSeconds: 20
      };

      const receiveResult = await sqsClient.send(new ReceiveMessageCommand(receiveMessageParams));
      const messages = receiveResult.Messages;

      if (messages.length === 0) {
        console.log("No messages to process");
        continue;
      }

      for (const message of messages) {
        try {
          const transactionData = JSON.parse(message.Body);
          await dbClient.updateTransaction(transactionData);

          const deleteMessageParams = {
            QueueUrl: queueUrl,
            ReceiptHandle: message.ReceiptHandle
          };

          await sqsClient.send(new DeleteMessageCommand(deleteMessageParams));
          console.log(`Processed and deleted message with ID: ${message.MessageId}`);
        } catch (error) {
          console.error(`Error processing message: ${message.MessageId}`, error);
        }
      }
    } catch (error) {
      console.error("Error receiving messages", error);
    }

    await new Promise(resolve => setTimeout(resolve, 1000)); // Throttle requests
  }
}

processMessages();